import{bV as e,aL as d,u as t,G as c}from"./chunks/framework.6JFQ6gON.js";const p=JSON.parse('{"title":"Python内置函数与关键字","description":"","frontmatter":{"date":"2026-04-08T17:38:48.000Z","title":"Python内置函数与关键字","categories":["人工智能技术","Python"],"tags":["编程语言","Python"]},"headers":[],"relativePath":"02.人工智能技术/01.Python/02.Python内置函数与关键字.md","filePath":"02.人工智能技术/01.Python/02.Python内置函数与关键字.md"}'),r={name:"02.人工智能技术/01.Python/02.Python内置函数与关键字.md"};function s(n,o,i,l,a,g){return d(),t("div",null,[...o[0]||(o[0]=[c(`<h1 id="python中的内置函数" tabindex="-1">Python中的内置函数 <a class="header-anchor" href="#python中的内置函数" aria-label="Permalink to &quot;Python中的内置函数&quot;">​</a></h1><h3 id="内置函数" tabindex="-1">内置函数 <a class="header-anchor" href="#内置函数" aria-label="Permalink to &quot;内置函数&quot;">​</a></h3><p>Python 之所以强大，很大程度上归功于其“自带电池”的理念。内置函数就是这些电池中最核心的一部分，它们无需导入任何模块即可直接使用，覆盖了从基础运算、数据处理到系统交互的方方面面。</p><table tabindex="0"><thead><tr><th></th><th></th><th>Built-in Functions</th><th></th><th></th></tr></thead><tbody><tr><td><code>abs()</code></td><td><code>delattr()</code></td><td><code>hash()</code></td><td><code>memoryview()</code></td><td><code>set()</code></td></tr><tr><td><code>all()</code></td><td><code>dict()</code></td><td><code>help()</code></td><td><code>min()</code></td><td><code>setattr()</code></td></tr><tr><td><code>any()</code></td><td><code>dir()</code></td><td><code>hex()</code></td><td><code>next()</code></td><td><code>slice()</code></td></tr><tr><td><code>ascii()</code></td><td><code>divmod()</code></td><td><code>id()</code></td><td><code>object()</code></td><td><code>sorted()</code></td></tr><tr><td><code>bin()</code></td><td><code>enumerate()</code></td><td><code>input()</code></td><td><code>oct()</code></td><td><code>staticmethod()</code></td></tr><tr><td><code>bool()</code></td><td><code>eval()</code></td><td><code>int()</code></td><td><code>open()</code></td><td><code>str()</code></td></tr><tr><td><code>breakpoint()</code></td><td><code>exec()</code></td><td><code>isinstance()</code></td><td><code>ord()</code></td><td><code>sum()</code></td></tr><tr><td><code>bytearray()</code></td><td><code>filter()</code></td><td><code>issubclass()</code></td><td><code>pow()</code></td><td><code>super()</code></td></tr><tr><td><code>bytes()</code></td><td><code>float()</code></td><td><code>iter()</code></td><td><code>print()</code></td><td><code>tuple()</code></td></tr><tr><td><code>callable()</code></td><td><code>format()</code></td><td><code>len()</code></td><td><code>property()</code></td><td><code>type()</code></td></tr><tr><td><code>chr()</code></td><td><code>frozenset()</code></td><td><code>list()</code></td><td><code>range()</code></td><td><code>vars()</code></td></tr><tr><td><code>classmethod()</code></td><td><code>getattr()</code></td><td><code>locals()</code></td><td><code>repr()</code></td><td><code>zip()</code></td></tr><tr><td><code>compile()</code></td><td><code>globals()</code></td><td><code>map()</code></td><td><code>reversed()</code></td><td><code>__import__()</code></td></tr><tr><td><code>complex()</code></td><td><code>hasattr()</code></td><td><code>max()</code></td><td><code>round()</code></td><td></td></tr></tbody></table><hr><h4 id="数学与运算类" tabindex="-1">数学与运算类 <a class="header-anchor" href="#数学与运算类" aria-label="Permalink to &quot;数学与运算类&quot;">​</a></h4><p>这一类函数主要用于处理数值计算，是科学计算和逻辑判断的基础。</p><ul><li><p><strong><code>abs(x)</code></strong>：返回数字的绝对值。</p></li><li><p><strong><code>divmod(a, b)</code></strong>：同时返回商和余数，相当于 <code>(a // b, a % b)</code>。</p></li><li><p><strong><code>pow(x, y[, z])</code></strong>：返回 x 的 y 次方；如果有 z，则返回 <code>(x**y) % z</code>。</p></li><li><p><strong><code>round(number[, ndigits])</code></strong>：对浮点数进行四舍五入，其中<code>ndigits</code>为可选参数。</p><ul><li><code>ndigits &gt; 0</code>，保留指定的小数位数，例如 <code>round(3.141592653, 2)</code>返回结果为 <code>3.14</code>。</li><li><code>ndigits = 0</code>，四舍五入到最接近的整数，例如 <code>round(2.7)</code>，返回结果是 <code>3</code>。</li><li><code>ndigits &lt; 0</code>，对整数部分进行四舍五入，例如 <code>round(324.123123, -2)</code>返回的结果是 <code>300.0</code>。</li></ul></li><li><p><strong><code>sum(iterable[, start])</code></strong>：对序列求和，<code>start</code>参数可以指定起始值。</p></li><li><p><strong><code>max(iterable)</code> / <code>min(iterable)</code></strong>：获取最大值或最小值，支持传入 <code>key</code> 函数进行自定义比较。</p></li></ul><h4 id="类型转换与构造类" tabindex="-1">类型转换与构造类 <a class="header-anchor" href="#类型转换与构造类" aria-label="Permalink to &quot;类型转换与构造类&quot;">​</a></h4><p>Python 是动态类型语言，类型转换非常频繁。这些函数既是转换工具，也是对象的构造器。</p><ul><li><strong><code>int(x, base=10)</code></strong>：将字符串或数字转为整数，支持进制转换（如二进制转十进制）。</li><li><strong><code>float(x)</code></strong>：转为浮点数。</li><li><strong><code>str(obj)</code></strong>：将对象转为字符串。</li><li><strong><code>bool(x)</code></strong>：转为布尔值（0、空序列为 <code>False</code>）。</li><li><strong><code>list()</code>, <code>tuple()</code>, <code>set()</code>, <code>dict()</code></strong>：分别用于创建列表、元组、集合和字典。</li><li><strong><code>chr(i)</code> / <code>ord(c)</code></strong>：ASCII 码与字符的互转。<code>chr(65)</code> 返回 &#39;A&#39;，<code>ord(&#39;A&#39;)</code> 返回 65。</li><li><strong><code>bin()</code>, <code>hex()</code>, <code>oct()</code></strong>：将整数分别转换为二进制、十六进制和八进制字符串。</li></ul><h4 id="迭代器与序列处理" tabindex="-1">迭代器与序列处理 <a class="header-anchor" href="#迭代器与序列处理" aria-label="Permalink to &quot;迭代器与序列处理&quot;">​</a></h4><p>处理数据集合时，这些函数能帮你遍历和操作数据。</p><ul><li><strong><code>len(s)</code></strong>：获取容器长度。</li><li><strong><code>range(start, stop, step)</code></strong>：生成不可变的整数序列。</li><li><strong><code>enumerate(iterable)</code></strong>：在循环中同时获取索引和元素值。</li><li><strong><code>zip(\\*iterables)</code></strong>：将多个列表对应位置的元素打包成元组，常用于并行遍历。</li><li><strong><code>map(function, iterable)</code></strong>：将函数应用于序列的每个元素。</li><li><strong><code>filter(function, iterable)</code></strong>：根据函数返回的 <code>True/False</code> 过滤序列元素。</li><li><strong><code>reversed(seq)</code></strong>：返回反向迭代器，不修改原数据。</li><li><strong><code>sorted(iterable)</code></strong>：返回排序后的新列表，原数据不变。</li><li><strong><code>all(iterable)</code> / <code>any(iterable)</code></strong>：判断序列中是否“全为真”或“有一个为真”。</li></ul><h4 id="对象操作与反射" tabindex="-1">对象操作与反射 <a class="header-anchor" href="#对象操作与反射" aria-label="Permalink to &quot;对象操作与反射&quot;">​</a></h4><p>当你需要动态地检查或修改对象属性时，这些函数非常有用。</p><ul><li><strong><code>type(obj)</code></strong>：查看对象类型，也可以用来动态创建类。</li><li><strong><code>id(obj)</code></strong>：返回对象的内存地址。</li><li><strong><code>isinstance(obj, classinfo)</code></strong>：判断对象是否是某个类的实例，比 <code>type()</code> 更推荐，因为它支持继承判断。</li><li><strong><code>callable(obj)</code></strong>：判断对象是否可被调用（即是否是函数）。</li><li><strong><code>getattr(obj, name)</code></strong>：获取对象的属性值。</li><li><strong><code>setattr(obj, name, value)</code></strong>：设置对象的属性值。</li><li><strong><code>hasattr(obj, name)</code></strong>：判断对象是否有某个属性。</li><li><strong><code>delattr(obj, name)</code></strong>：删除对象的属性。</li><li><strong><code>hash(obj)</code></strong>：获取对象的哈希值，用于集合和字典的键。</li><li><strong><code>dir(obj)</code></strong>：列出对象的所有属性和方法。</li></ul><h4 id="输入输出与系统交互" tabindex="-1">输入输出与系统交互 <a class="header-anchor" href="#输入输出与系统交互" aria-label="Permalink to &quot;输入输出与系统交互&quot;">​</a></h4><p>负责程序与外部环境（用户、文件、系统）的沟通。</p><ul><li><strong><code>print(\\*objects)</code></strong>：打印输出，支持 <code>sep</code>（分隔符）和 <code>end</code>（结尾符）参数。</li><li><strong><code>input(prompt)</code></strong>：暂停程序，等待用户输入，始终返回字符串。</li><li><strong><code>open(file, mode)</code></strong>：打开文件，返回文件对象，是文件操作的第一步。</li><li><strong><code>help(object)</code></strong>：调出内置的帮助文档，相当于查阅说明书。</li><li><strong><code>breakpoint()</code></strong>：Python 3.7+ 新增，直接在代码中设置断点进入调试器。</li><li><strong><code>globals()</code> / <code>locals()</code></strong>：分别返回当前全局和局部作用域的变量字典。</li><li><strong><code>eval(expression)</code></strong>：将字符串当作 Python 表达式执行（<strong>注意安全风险</strong>）。</li><li><strong><code>exec(object)</code></strong>：动态执行 Python 代码块（<strong>注意安全风险</strong>）。</li></ul><h4 id="其他重要函数" tabindex="-1">其他重要函数 <a class="header-anchor" href="#其他重要函数" aria-label="Permalink to &quot;其他重要函数&quot;">​</a></h4><ul><li><strong><code>property()</code></strong>：用于定义属性，可以将方法伪装成属性调用。</li><li><strong><code>staticmethod()</code> / <code>classmethod()</code></strong>：定义静态方法和类方法。</li><li><strong><code>super()</code></strong>：调用父类的方法，常用于继承场景。</li><li><strong><code>object()</code></strong>：所有类的基类。</li><li><strong><code>slice()</code></strong>：创建切片对象，用于复杂的切片操作。</li></ul><h3 id="关键字" tabindex="-1">关键字 <a class="header-anchor" href="#关键字" aria-label="Permalink to &quot;关键字&quot;">​</a></h3><p>在 Python 的编程世界里，我们每天都在和变量、函数、类打交道。但你是否注意过那些“不能用作变量名”的特殊单词？比如 <code>if</code>、<code>for</code>、<code>class</code>、<code>def</code>？</p><p>这些就是 <strong>Python 关键字（Keywords）</strong>，也被称为<strong>保留字</strong>。它们是 Python 语言的“基石”，拥有特殊的语法含义，是解释器理解你代码意图的关键。</p><hr><h4 id="什么是关键字" tabindex="-1">什么是关键字？ <a class="header-anchor" href="#什么是关键字" aria-label="Permalink to &quot;什么是关键字？&quot;">​</a></h4><p>简单来说，关键字就是 Python 内部已经“预定”好的单词。你不能把它们用作变量名、函数名或类名，否则会引发 <code>SyntaxError</code>（语法错误）。</p><p>Python 是严格区分大小写的语言，所以 <code>True</code> 是关键字，但 <code>true</code> 就不是；<code>if</code> 是关键字，但 <code>If</code> 就可以作为变量名（虽然不推荐）。</p><p>你可以随时通过以下代码查看当前 Python 版本的所有关键字：</p><div class="language-python vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">python</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">import</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> keyword</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 打印所有关键字列表</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">print</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(keyword.kwlist)</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 判断某个字符串是否是关键字</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">print</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(keyword.iskeyword(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;if&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">))  </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 输出: True</span></span></code></pre></div><hr><h4 id="python关键字全景图" tabindex="-1">Python关键字全景图 <a class="header-anchor" href="#python关键字全景图" aria-label="Permalink to &quot;Python关键字全景图&quot;">​</a></h4><p>截至 Python 3.12，共有 <strong>35 个</strong>核心关键字。为了让你不再死记硬背，我将它们按功能分成了六类。</p><table tabindex="0"><thead><tr><th>类别</th><th>关键字</th></tr></thead><tbody><tr><td><strong>逻辑与布尔</strong></td><td><code>True</code>, <code>False</code>, <code>None</code>, <code>and</code>, <code>or</code>, <code>not</code>, <code>is</code>, <code>in</code></td></tr><tr><td><strong>流程控制</strong></td><td><code>if</code>, <code>elif</code>, <code>else</code>, <code>for</code>, <code>while</code>, <code>break</code>, <code>continue</code>, <code>pass</code></td></tr><tr><td><strong>函数与类</strong></td><td><code>def</code>, <code>class</code>, <code>return</code>, <code>yield</code>, <code>lambda</code>, <code>global</code>, <code>nonlocal</code></td></tr><tr><td><strong>异常处理</strong></td><td><code>try</code>, <code>except</code>, <code>finally</code>, <code>raise</code>, <code>assert</code></td></tr><tr><td><strong>模块与上下文</strong></td><td><code>import</code>, <code>from</code>, <code>as</code>, <code>with</code>, <code>del</code></td></tr><tr><td><strong>异步编程</strong></td><td><code>async</code>, <code>await</code></td></tr></tbody></table><hr><h4 id="核心关键字详解" tabindex="-1">核心关键字详解 <a class="header-anchor" href="#核心关键字详解" aria-label="Permalink to &quot;核心关键字详解&quot;">​</a></h4><p><strong>逻辑与布尔</strong></p><p>这些关键字用于处理真假值和逻辑关系，是所有条件判断的基础。</p><ul><li><strong><code>True</code> / <code>False</code></strong>：代表真和假。注意首字母必须大写。</li><li><strong><code>None</code></strong>：代表“空”或“无”，类似于其他语言中的 <code>null</code>。</li><li><strong><code>and</code> / <code>or</code> / <code>not</code></strong>：逻辑与、或、非。例如 <code>if x &gt; 0 and x &lt; 10:</code>。</li><li><strong><code>is</code></strong>：用于判断两个变量是否指向同一个内存地址（身份比较），不同于 <code>==</code>（值比较）。</li><li><strong><code>in</code></strong>：用于判断元素是否存在于序列（如列表、字符串）中。</li></ul><p><strong>流程控制</strong></p><p>没有这些关键字，代码只能从上到下顺序执行，它们赋予了代码“思考”和“循环”的能力。</p><ul><li><strong><code>if</code> / <code>elif</code> / <code>else</code></strong>：条件判断的三剑客。Python 没有 <code>switch-case</code>（3.10 之前），全靠它们。</li><li><strong><code>for</code> / <code>while</code></strong>：循环结构。<code>for</code> 用于遍历序列，<code>while</code> 用于满足条件时循环。</li><li><strong><code>break</code> / <code>continue</code></strong>：<code>break</code> 用于彻底跳出循环，<code>continue</code> 用于跳过本次循环的剩余代码，直接进入下一次循环。</li><li><strong><code>pass</code></strong>：这是一个“占位符”。当你写了一个 <code>if</code> 语句或函数定义，但暂时不想写具体代码时，用 <code>pass</code> 来防止报错。</li></ul><p><strong>函数与类</strong></p><p>这是 Python 面向对象和函数式编程的核心。</p><ul><li><strong><code>def</code></strong>：定义函数的开始。</li><li><strong><code>class</code></strong>：定义类的开始。</li><li><strong><code>return</code></strong>：从函数中返回值。</li><li><strong><code>lambda</code></strong>：用于定义匿名函数（一行函数），常用于 <code>map</code> 或 <code>filter</code> 中。</li><li><strong><code>yield</code></strong>：用于生成器函数。它会让函数“暂停”并返回一个值，下次调用时从暂停处继续，极大地节省内存。</li><li><strong><code>global</code> / <code>nonlocal</code></strong>：用于修改变量的作用域。<code>global</code> 用于修改全局变量， <code>nonlocal</code> 用于修改嵌套函数中的外层变量。</li></ul><p><strong>异常处理</strong></p><p>程序难免会出错，这些关键字能防止程序直接崩溃。</p><ul><li><strong><code>try</code> / <code>except</code></strong>：尝试执行可能出错的代码，如果出错则捕获并处理。</li><li><strong><code>finally</code></strong>：无论是否出错，这段代码都会执行（常用于关闭文件、释放资源）。</li><li><strong><code>raise</code></strong>：主动引发一个异常。</li><li><strong><code>assert</code></strong>：断言。如果条件为 <code>False</code>，则程序立即报错并停止。常用于调试。</li></ul><p><strong>模块与上下文：资源管理大师</strong></p><ul><li><strong><code>import</code> / <code>from</code> / <code>as</code></strong>：用于导入模块。<code>as</code>可以给模块起别名，比如 <code>import numpy as np</code>。</li><li><strong><code>with</code></strong>：上下文管理器。最常用于文件操作，它能自动帮你关闭文件，无需手动<code>close()</code>。</li><li><strong><code>del</code></strong>：删除对象的引用，相当于告诉 Python “我不需要这个变量了”，触发垃圾回收。</li></ul><p><strong>异步编程：现代高并发利器</strong></p><ul><li><strong><code>async</code> / <code>await</code></strong>：用于编写并发代码。<code>async</code> 定义一个协程，<code>await</code> 用于等待一个异步操作完成，让程序在等待时可以去处理其他任务。</li></ul><hr><h4 id="软关键字与特殊标识符" tabindex="-1">软关键字与特殊标识符 <a class="header-anchor" href="#软关键字与特殊标识符" aria-label="Permalink to &quot;软关键字与特殊标识符&quot;">​</a></h4><p>除了上述 35 个硬性规定的关键字，Python 3.10 引入了<strong>结构化模式匹配</strong>，带来了几个“软关键字”：<code>match</code>、<code>case</code> 和 <code>_</code>（通配符）。</p><p>它们被称为“软”关键字，是因为它们只在特定的语法结构（<code>match</code> 语句）中才具有特殊含义，在其他地方你仍然可以将它们用作变量名（虽然极度不推荐这样做，以免混淆）。</p><p>此外，还有一些特殊的标识符命名规则，虽然不是关键字，但也需要留意：</p><ul><li><strong><code>_var</code></strong>：以单下划线开头的变量，约定俗成地表示“私有”或“内部使用”。</li><li><strong><code>__var__</code></strong>：以双下划线开头和结尾的变量（如<code>__init__</code>），由系统定义，切勿随意命名。</li></ul>`,59)])])}const u=e(r,[["render",s]]);export{p as __pageData,u as default};
